const assessment = $('Assessment to DB').first().json.assessment_data;

const preference = assessment.nutrition.foodPreference || "";
const allergies = assessment.allergies.selected || [];

let foods = items;

// ------------------------------
// Diet Preference Filter
// ------------------------------

foods = foods.filter(food => {

  const row = food.json;

  // Normalize preference
  const pref = preference.toLowerCase();

  if (pref.includes("vegan"))
    return Number(row["Vegan"]) === 1;

  if (pref.includes("vegetarian") && !pref.includes("non"))
    return Number(row["Vegetarian"]) === 1;

  if (pref.includes("eggetarian"))
    return Number(row["Eggetarian"]) === 1;

  if (pref.includes("pisc"))
    return Number(row["Piscetarian"]) === 1;

  if (pref.includes("non-veg") || pref.includes("non vegetarian"))
    return Number(row["Non Vegetarian"]) === 1;

  return true;
});

// ------------------------------
// Allergy Filter
// ------------------------------

if (allergies.some(a => a.includes("MLK")))
  foods = foods.filter(f => Number(f.json.MLK) !== 1);

if (allergies.some(a => a.includes("HYP")))
  foods = foods.filter(f => Number(f.json.HYP) !== 1);

if (allergies.some(a => a.includes("PE")))
  foods = foods.filter(f => Number(f.json.PE) !== 1);

if (allergies.some(a => a.includes("SOY")))
  foods = foods.filter(f => Number(f.json.SOY) !== 1);

if (allergies.some(a => a.includes("EGG")))
  foods = foods.filter(f => Number(f.json.EGG) !== 1);

if (allergies.some(a => a.includes("SF")))
  foods = foods.filter(f => Number(f.json.SF) !== 1);

console.log("Food Preference:", preference);
console.log("Allergies:", allergies);
console.log("Foods after filtering:", foods.length);

return foods;

let assessment = null;

const foods = [];
const supplements = [];

for (const item of items) {

  // Assessment
  if (item.json.assessment_data) {
    assessment = item.json;
    continue;
  }

  // Food Database
  if ("Food" in item.json) {
    foods.push(item.json);
    continue;
  }

  // Supplement Database
  if ("SupplementName" in item.json) {
    supplements.push(item.json);
    continue;
  }

}

return [
  {
    json: {
      assessment,
      foods,
      supplements
    }
  }
];

let text = $json.response.trim();

// Find first JSON object
const start = text.indexOf('{');

let depth = 0;
let end = -1;

for (let i = start; i < text.length; i++) {
  if (text[i] === '{') depth++;
  if (text[i] === '}') depth--;

  if (depth === 0) {
    end = i;
    break;
  }
}

if (start === -1 || end === -1) {
  throw new Error('Could not find complete JSON object');
}

const jsonText = text.substring(start, end + 1);

return [
  {
    json: JSON.parse(jsonText)
  }
];

